{"code_block": "claims = [
    {
        "id": "a_1",
        "page": 1,
        "type": "numerical-data",
        "text": "According to the Bureau of Economic Analysis, U.S. real GDP grew at an annual rate of 1.6%.",
        "metadata": {
            "organization": [
                "Bureau of Economic Analysis"
            ],
            "country": "United States",
            "indicator": "real GDP growth",
            "value": 1.6,
            "unit": "percent",
            "period": "third quarter of 2024",
            "rate_description": "annual rate"
        }
    },
    {
        "id": "a_2",
        "page": 1,
        "type": "time-sensitive",
        "text": "The growth occurred in the third quarter of 2024.",
        "metadata": {
            "organization": [
                "Bureau of Economic Analysis"
            ],
            "country": "United States",
            "indicator": "real GDP growth",
            "value": 1.6,
            "unit": "percent",
            "period": "third quarter of 2024",
            "rate_description": "annual rate"
        }
    }
]

# Build fact table and check contradictions
fact_table = {}
for claim in claims:
    key = (claim['metadata']['indicator'], claim['metadata']['organization'][0], claim['metadata']['period'], claim['metadata']['rate_description'])
    fact_table.setdefault(key, []).append((claim['id'], claim['metadata']['value'], claim['type']))

contradictions = []
for key, entries in fact_table.items():
    if len(entries) > 1:
        # Extract values
        values = [(entry[0], entry[1]) for entry in entries]
        # Check for mismatches
        unique_vals = set(val for _, val in values)
        if len(unique_vals) > 1:
            # Contradiction found
            # Determine severity
            if all(val[1] == entries[0][2] for val in entries):
                severity = "critical"
            else:
                severity = "major"
            # Confidence is 1.0 since values are from structured metadata
            confidence = 1.0
            # Summarize
            ids = [entry[0] for entry in entries]
            contradictions.append({
                "claim_a_id": ids[0],
                "claim_b_id": ids[1],
                "severity": severity,
                "confidence": confidence,
                "summary": f"Claim {ids[0]} and Claim {ids[1]} report different values for {key[0]} for {key[2]}: Claim {ids[0]} states {entries[0][1]}% while Claim {ids[1]} implies {entries[1][1]}%"
            })

result = {"contradictions": contradictions}
print(result)"}

